/**
 * Batch Quiz Generator — Part 4 (14 series)
 * Run: node .tools/build-quizzes-batch4.js
 */
const fs = require('fs');
const path = require('path');

function encode(answer, salt) {
    const json = JSON.stringify(answer);
    let shifted = '';
    for (let i = 0; i < json.length; i++) shifted += String.fromCharCode(json.charCodeAt(i) ^ salt.charCodeAt(i % salt.length));
    return Buffer.from(shifted, 'binary').toString('base64');
}
function buildQuiz(c) {
    return { series: c.series, title: c.title, version: 1, totalParts: c.totalParts, security: { method: "xor-b64", salt: c.salt },
        questions: c.questions.map(q => { q.answer = encode(q._answer, c.salt); delete q._answer; return q; }) };
}
function writeQuiz(quiz) {
    const d = path.join(__dirname, '..', 'pages', 'series', quiz.series);
    if (!fs.existsSync(d)) { console.warn('  ⚠ Missing:', quiz.series); return false; }
    fs.writeFileSync(path.join(d, 'quiz.json'), JSON.stringify(quiz, null, 2)); return true;
}

