    { id: "aw-q006", part: 6, difficulty: "advanced", type: "ethical", question: "Should companies be required to disclose when AI makes decisions that significantly affect people's lives?", scenario: "AI is used for: hiring (resume screening), lending (credit decisions), healthcare (diagnosis), and criminal justice (recidivism prediction). Most affected individuals don't know AI was involved.", options: [{ label: "Mandatory disclosure for all AI-assisted decisions", framework: "Transparency — people have the right to know" }, { label: "Only for adverse decisions (rejections, denials)", framework: "Minimal burden — disclose when it matters" }, { label: "No requirement — the decision quality matters, not the method", framework: "Outcome-focused — judge by results" }, { label: "Disclosure + right to human review (algorithmic due process)", framework: "Full accountability — know and contest" }], _answer: 3, explanation: "The EU AI Act and proposed US legislation converge on disclosure + contestability for high-risk AI decisions. People should know AI was involved AND have the ability to request human review of adverse decisions.", articleSlug: "ai-in-the-wild-transparency", tags: ["transparency", "regulation", "ethics"] }
