const sensorsActuators = buildQuiz({ series: "sensors-actuators", title: "Sensors & Actuators", salt: "sens-act-2026", totalParts: 14, questions: [
    { id: "sa-q001", part: 1, difficulty: "beginner", type: "mcq", question: "What is the fundamental difference between a sensor and an actuator?", options: ["Sensors are digital, actuators are analog", "Sensors measure/detect physical quantities, actuators produce physical action/movement", "Sensors are expensive, actuators are cheap", "Sensors need power, actuators don't"], _answer: 1, explanation: "Sensors convert physical quantities (temperature, pressure, light) into electrical signals for measurement. Actuators convert electrical signals into physical action (motion, heat, light). They're the input and output of control systems.", articleSlug: "sensors-actuators-fundamentals", tags: ["sensors", "actuators", "fundamentals"] },
    { id: "sa-q002", part: 2, difficulty: "intermediate", type: "true-false", question: "A thermocouple measures temperature by generating a voltage proportional to temperature difference between two junctions of dissimilar metals.", _answer: true, explanation: "Seebeck effect: a junction of two different metals generates a voltage proportional to temperature (Type K: chromel-alumel, ~41μV/°C). Range: -200°C to +1350°C. No excitation needed (self-generating sensor).", articleSlug: "sensors-actuators-temperature", tags: ["thermocouple", "temperature"] },
    { id: "sa-q003", part: 3, difficulty: "intermediate", type: "fill-blank", question: "A strain gauge measures deformation by changing its electrical ___.", _answer: "resistance", acceptAlso: ["resistance value"], explanation: "Strain gauges: thin metallic foil bonded to a structure. When the structure deforms, the foil stretches → resistance changes (ΔR/R = GF × ε, where GF ≈ 2 for metal gauges). Used in load cells, pressure sensors, and structural monitoring.", articleSlug: "sensors-actuators-strain", tags: ["strain gauge", "resistance"] },
    { id: "sa-q004", part: 4, difficulty: "intermediate", type: "matching", question: "Match each sensor type to what it measures:", pairs: { left: ["Accelerometer", "Proximity sensor (inductive)", "Photodiode", "Load cell"], right: ["Acceleration/vibration/tilt", "Presence of metal objects without contact", "Light intensity (photocurrent)", "Force/weight (via strain gauges in Wheatstone bridge)"] }, _answer: [0, 1, 2, 3], explanation: "Accelerometers: MEMS capacitive — measures acceleration (phones, airbags). Inductive proximity: oscillator damped by eddy currents in metal. Photodiode: photon → electron-hole pairs. Load cell: 4 strain gauges in bridge circuit.", articleSlug: "sensors-actuators-types", tags: ["accelerometer", "proximity", "load cell"] },
    { id: "sa-q005", part: 5, difficulty: "advanced", type: "calculation", question: "A 10-bit ADC with 5V reference reads a temperature sensor that outputs 10mV/°C. What temperature resolution can the system achieve?", formula: "Resolution = V_ref / (2^bits) / sensitivity", _answer: 0.49, unit: "°C", tolerance: 0.02, explanation: "ADC resolution = 5V / 1024 = 4.88mV per step. Sensor: 10mV/°C. Temperature resolution = 4.88mV / (10mV/°C) = 0.49°C. Each ADC count represents 0.49°C. For better resolution: use 12-bit ADC (0.12°C) or amplify the signal.", articleSlug: "sensors-actuators-signal-conditioning", tags: ["ADC", "resolution", "temperature"] },
    { id: "sa-q006", part: 6, difficulty: "advanced", type: "scenario", question: "You're designing a system to detect water leaks in a data center floor (500m² area). Which sensing approach?", scenario: { context: "Critical data center. Water leak from cooling pipes must be detected within 30 seconds, located within 1m accuracy.", constraints: ["500m² raised floor area", "Must locate leak within 1m", "Response time: <30 seconds", "Minimal false alarms"] }, options: ["Discrete point sensors (one every 2m) — simple but blind between sensors", "Continuous sensing cable (conductive polymer along pipe routes) — detects anywhere along its length", "Humidity sensors in air handling — detects moisture increase", "Thermal imaging — water changes floor temperature pattern"], _answer: 1, explanation: "Conductive sensing cables detect water at ANY point along their length using TDR (Time Domain Reflectometry) to locate the exact position (±0.5m). Run along pipe routes. Covers entire area continuously, not just discrete points. Industry standard for data center leak detection.", articleSlug: "sensors-actuators-leak-detection", tags: ["leak detection", "sensing cable", "TDR"] }
]});

